package com.bank.ea.domain;
import jakarta.persistence.*; import jakarta.validation.constraints.NotBlank; import java.time.Instant;
@Entity @Table(name="projects") public class Project {
 public enum Stage { IDEA, DISCOVERY, DRAFT, SUBMITTED, UNDER_REVIEW, CONDITIONALLY_APPROVED, APPROVED, REJECTED, IMPLEMENTING, LIVE, CLOSED }
 @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @NotBlank @Column(nullable=false) private String name; private String code; private String sponsor; private String businessOwner; private String leadArchitect; @Enumerated(EnumType.STRING) @Column(nullable=false) private Stage stage=Stage.IDEA; private String startDate; private String targetDate; private String overallRisk;
 @Column(length=4000) private String problemStatement; @Column(length=4000) private String approvalAuthority; @Column(length=4000) private String mandatoryInformation; @Column(length=4000) private String existingTools; @Column(length=4000) private String ssoRequirements; @Column(length=4000) private String securityRequirements; @Column(length=4000) private String hostingRequirements; @Column(length=4000) private String retentionRequirements; @Column(length=4000) private String executiveReports; @Column(length=4000) private String auditEvidence; private String repositoryOwner; private String repositoryMaintainer; @Column(nullable=false,updatable=false) private Instant createdAt=Instant.now(); @Column(nullable=false) private Instant updatedAt=Instant.now(); @PreUpdate void updated(){updatedAt=Instant.now();}
 public Long getId(){return id;} public void setId(Long v){id=v;} public String getName(){return name;} public void setName(String v){name=v;} public String getCode(){return code;} public void setCode(String v){code=v;} public String getSponsor(){return sponsor;} public void setSponsor(String v){sponsor=v;} public String getBusinessOwner(){return businessOwner;} public void setBusinessOwner(String v){businessOwner=v;} public String getLeadArchitect(){return leadArchitect;} public void setLeadArchitect(String v){leadArchitect=v;} public Stage getStage(){return stage;} public void setStage(Stage v){stage=v;} public String getStartDate(){return startDate;} public void setStartDate(String v){startDate=v;} public String getTargetDate(){return targetDate;} public void setTargetDate(String v){targetDate=v;} public String getOverallRisk(){return overallRisk;} public void setOverallRisk(String v){overallRisk=v;} public String getProblemStatement(){return problemStatement;} public void setProblemStatement(String v){problemStatement=v;} public String getApprovalAuthority(){return approvalAuthority;} public void setApprovalAuthority(String v){approvalAuthority=v;} public String getMandatoryInformation(){return mandatoryInformation;} public void setMandatoryInformation(String v){mandatoryInformation=v;} public String getExistingTools(){return existingTools;} public void setExistingTools(String v){existingTools=v;} public String getSsoRequirements(){return ssoRequirements;} public void setSsoRequirements(String v){ssoRequirements=v;} public String getSecurityRequirements(){return securityRequirements;} public void setSecurityRequirements(String v){securityRequirements=v;} public String getHostingRequirements(){return hostingRequirements;} public void setHostingRequirements(String v){hostingRequirements=v;} public String getRetentionRequirements(){return retentionRequirements;} public void setRetentionRequirements(String v){retentionRequirements=v;} public String getExecutiveReports(){return executiveReports;} public void setExecutiveReports(String v){executiveReports=v;} public String getAuditEvidence(){return auditEvidence;} public void setAuditEvidence(String v){auditEvidence=v;} public String getRepositoryOwner(){return repositoryOwner;} public void setRepositoryOwner(String v){repositoryOwner=v;} public String getRepositoryMaintainer(){return repositoryMaintainer;} public void setRepositoryMaintainer(String v){repositoryMaintainer=v;} public Instant getCreatedAt(){return createdAt;} public Instant getUpdatedAt(){return updatedAt;}
}
